// CS Form 6 DOCX template (uploaded to Cloudinary admin storage)
const CS6_TEMPLATE_URL = "https://res.cloudinary.com/dsbu9k6yp/raw/upload/v1777099989/tunga-es/2026/file_gowj0f";
const JSZIP_CDN = "https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js";

// Load JSZip from CDN once, cache the promise
let _jszipPromise = null;
const loadJSZip = () => {
  if (typeof window === "undefined") return Promise.reject(new Error("SSR"));
  if (window.JSZip) return Promise.resolve(window.JSZip);
  if (_jszipPromise) return _jszipPromise;
  _jszipPromise = new Promise((resolve, reject) => {
    const s = document.createElement("script");
    s.src = JSZIP_CDN;
    s.onload = () => window.JSZip ? resolve(window.JSZip) : reject(new Error("JSZip load failed"));
    s.onerror = () => reject(new Error("JSZip script failed to load"));
    document.head.appendChild(s);
  });
  return _jszipPromise;
};

// Phase 2b: full text injection for simple fields.
// Injects: Name (Last/First/Middle), Date of Filing, Position, Salary,
//          Number of Working Days, Inclusive Dates, Date Actioned, 
//          Vacation/Sick credit table (6 cells: Total Earned, Less, Balance × VL, SL),
//          Days With Pay (in 7.C),
//          Other reason text, Whereabouts, Illness.
// Does NOT yet handle checkboxes (Phase 3) or signatures (Phase 4).
async function buildCS6Docx_v2(leave, withSig) {
  const JSZip = await loadJSZip();
  const resp = await fetch(CS6_TEMPLATE_URL);
  if (!resp.ok) throw new Error("Template fetch failed: HTTP " + resp.status);
  const buf = await resp.arrayBuffer();
  const zip = await JSZip.loadAsync(buf);

  const parseName = (full) => {
    const s = (full || "").trim();
    if (!s) return { last: "", first: "", middle: "" };
    if (s.includes(",")) {
      const [l1, rest] = s.split(/,\s*/);
      const tok = (rest || "").split(/\s+/).filter(Boolean);
      return { last: l1.trim(), first: tok[0] || "", middle: tok.slice(1).join(" ") };
    }
    const tok = s.split(/\s+/).filter(Boolean);
    if (tok.length === 1) return { last: tok[0], first: "", middle: "" };
    if (tok.length === 2) return { last: tok[1], first: tok[0], middle: "" };
    return { last: tok[tok.length - 1], first: tok[0], middle: tok.slice(1, -1).join(" ") };
  };
  const { last, first, middle } = parseName(leave.requester);

  const xe = (s) => String(s || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");

  // Helper: build a simple inline text run with given size
  const run = (txt, sz) => `<w:r><w:rPr><w:sz w:val="${sz||16}"/></w:rPr><w:t xml:space="preserve">${xe(txt)}</w:t></w:r>`;

  const docXml = zip.file("word/document.xml");
  if (!docXml) throw new Error("document.xml not found in template");
  let xml = await docXml.async("string");

  // ─── 1. Name fields (proven in Phase 2a) ───
  if (last)   xml = xml.replace(/<w:t>\(Last\)<\/w:t>/, `<w:t xml:space="preserve">${xe(last)}  </w:t></w:r><w:r><w:rPr><w:sz w:val="14"/></w:rPr><w:t>(Last)</w:t>`);
  if (first)  xml = xml.replace(/<w:t>\(First\)<\/w:t>/, `<w:t xml:space="preserve">${xe(first)}  </w:t></w:r><w:r><w:rPr><w:sz w:val="14"/></w:rPr><w:t>(First)</w:t>`);
  if (middle) xml = xml.replace(/<w:t>\(Middle\)<\/w:t>/, `<w:t xml:space="preserve">${xe(middle)}  </w:t></w:r><w:r><w:rPr><w:sz w:val="14"/></w:rPr><w:t>(Middle)</w:t>`);

  // ─── 2-7. SIMPLE TEXT FIELDS — replace the WHOLE label+space+tab zone with our content ───
  // Strategy: for each label, find the unique full pattern including the trailing tab(s),
  // then replace with the same structure but containing our value as plain text.
  // Using normal-baseline run (no w:position offset) avoids font kerning glitches.

  // DATE OF FILING — covers: label, spacing-46 space-run, single-underline tab, plain tab
  const dateBlock = `<w:t>DATE OF FILING</w:t></w:r><w:r><w:rPr><w:spacing w:val="46"/><w:position w:val="2"/><w:sz w:val="16"/></w:rPr><w:t xml:space="preserve"> </w:t></w:r><w:r><w:rPr><w:position w:val="2"/><w:sz w:val="16"/><w:u w:val="single"/></w:rPr><w:tab/></w:r><w:r><w:rPr><w:position w:val="2"/><w:sz w:val="16"/></w:rPr><w:tab/></w:r>`;
  if (xml.includes(dateBlock)) {
    xml = xml.replace(dateBlock, `<w:t xml:space="preserve">DATE OF FILING </w:t></w:r><w:r><w:rPr><w:sz w:val="16"/><w:u w:val="single"/></w:rPr><w:t xml:space="preserve"> ${xe(leave.dateFiled||"")} </w:t></w:r><w:r><w:rPr><w:sz w:val="16"/></w:rPr><w:t xml:space="preserve">          </w:t></w:r>`);
  }

  // POSITION — covers: label, spacing-43 space, single-underline tab
  const posBlock = `<w:t>POSITION</w:t></w:r><w:r><w:rPr><w:spacing w:val="43"/><w:sz w:val="16"/></w:rPr><w:t xml:space="preserve"> </w:t></w:r><w:r><w:rPr><w:sz w:val="16"/><w:u w:val="single"/></w:rPr><w:tab/></w:r>`;
  if (xml.includes(posBlock)) {
    xml = xml.replace(posBlock, `<w:t xml:space="preserve">POSITION  </w:t></w:r><w:r><w:rPr><w:sz w:val="16"/><w:u w:val="single"/></w:rPr><w:t xml:space="preserve">${xe(leave.position||"")}</w:t></w:r><w:r><w:rPr><w:sz w:val="16"/></w:rPr><w:tab/></w:r>`);
  }

  // SALARY — covers: label, spacing-47 space, single-underline tab
  const salBlock = `<w:t>SALARY</w:t></w:r><w:r><w:rPr><w:spacing w:val="47"/><w:sz w:val="16"/></w:rPr><w:t xml:space="preserve"> </w:t></w:r><w:r><w:rPr><w:sz w:val="16"/><w:u w:val="single"/></w:rPr><w:tab/></w:r>`;
  if (xml.includes(salBlock)) {
    xml = xml.replace(salBlock, `<w:t xml:space="preserve">SALARY  </w:t></w:r><w:r><w:rPr><w:sz w:val="16"/><w:u w:val="single"/></w:rPr><w:t xml:space="preserve">${xe(leave.salary||"")}</w:t></w:r><w:r><w:rPr><w:sz w:val="16"/></w:rPr><w:tab/></w:r>`);
  }

  // 6.C NUMBER OF WORKING DAYS APPLIED FOR — second occurrence of "FOR" (first is in title)
  const forTarget = `<w:t>FOR</w:t></w:r>`;
  const forIdx1 = xml.indexOf(forTarget);
  if (forIdx1 >= 0) {
    const forIdx2 = xml.indexOf(forTarget, forIdx1 + 1);
    if (forIdx2 >= 0) {
      const before = xml.slice(0, forIdx2);
      const after = xml.slice(forIdx2 + forTarget.length);
      xml = before + `<w:t xml:space="preserve">FOR  ${xe(String(leave.days||""))}</w:t></w:r>` + after;
    }
  }

  // INCLUSIVE DATES (only one occurrence)
  xml = xml.replace(
    `<w:t>DATES</w:t></w:r>`,
    `<w:t xml:space="preserve">DATES  ${xe((leave.startDate&&leave.endDate)?(leave.startDate+" to "+leave.endDate):"")}</w:t></w:r>`
  );

  // "As of " — followed by underline-tab. Replace label+tab area.
  const asOfBlock = `<w:t xml:space="preserve">As of </w:t></w:r><w:r><w:rPr><w:rFonts w:ascii="Times New Roman"/><w:sz w:val="20"/><w:u w:val="thick"/></w:rPr><w:tab/></w:r>`;
  if (xml.includes(asOfBlock)) {
    xml = xml.replace(asOfBlock, `<w:t xml:space="preserve">As of </w:t></w:r><w:r><w:rPr><w:rFonts w:ascii="Times New Roman"/><w:sz w:val="20"/><w:u w:val="single"/></w:rPr><w:t xml:space="preserve">${xe(leave.dateActioned||leave.dateFiled||"")}</w:t></w:r>`);
  }

  // ─── 8. Credit table: 6 empty cells in order ───
  // The pattern is: <w:tcW w:w="1580|1579" .../></w:tcPr><w:p ...><w:pPr>...empty pPr...</w:pPr></w:p></w:tc>
  // They appear 6 times in order: VL Total, SL Total, VL Less, SL Less, VL Balance, SL Balance
  const _snap = leave.snapshotCredits || {};
  const _hasSnap = Object.keys(_snap).length > 0 && (_snap.vacationLeave || _snap.sickLeave);
  const myUserCredits = _hasSnap ? _snap : (typeof window !== "undefined" && window.__tesCurrentCredits) || _snap;
  const vlTotal = myUserCredits.vacationLeave || 0;
  const slTotal = myUserCredits.sickLeave || 0;
  const vlLess = leave.type === "Vacation Leave" ? leave.days : 0;
  const slLess = leave.type === "Sick Leave" ? leave.days : 0;
  const vlBal = vlTotal - vlLess;
  const slBal = slTotal - slLess;
  const creditValues = [String(vlTotal), String(slTotal), String(vlLess), String(slLess), String(vlBal), String(slBal)];

  // Match the empty-cell pattern and replace one at a time with values
  let creditIdx = 0;
  const emptyCellRegex = /<w:tcW w:w="(?:1579|1580)" w:type="dxa"\/><\/w:tcPr><w:p w:rsidR="005002FD" w:rsidRDefault="005002FD"><w:pPr><w:pStyle w:val="TableParagraph"\/><w:rPr><w:rFonts w:ascii="Times New Roman"\/><w:sz w:val="12"\/><\/w:rPr><\/w:pPr><\/w:p><\/w:tc>/;
  while (creditIdx < 6) {
    const m = xml.match(emptyCellRegex);
    if (!m) break;
    const widthAttr = m[0].match(/w:w="(\d+)"/)[1];
    const val = creditValues[creditIdx];
    const replacement = `<w:tcW w:w="${widthAttr}" w:type="dxa"/></w:tcPr><w:p w:rsidR="005002FD" w:rsidRDefault="005002FD"><w:pPr><w:pStyle w:val="TableParagraph"/><w:jc w:val="center"/><w:rPr><w:rFonts w:ascii="Times New Roman"/><w:sz w:val="16"/></w:rPr></w:pPr><w:r><w:rPr><w:rFonts w:ascii="Times New Roman"/><w:sz w:val="16"/></w:rPr><w:t>${xe(val)}</w:t></w:r></w:p></w:tc>`;
    xml = xml.replace(emptyCellRegex, replacement);
    creditIdx++;
  }

  // ─── PHASE 3: Mark the selected leave type's checkbox ───
  // TWO-PRONGED approach (belt-and-suspenders):
  // (A) Edit the VML <v:shape> path attribute to add diagonal ✓ strokes inside the actual box
  // (B) Strip the EMF (o:gfxdata) fallback to force Word to use the VML path
  // (C) Also add a small inline ☑ before the label as a textual backup, in case Word still uses EMF

  // Map leave type → box index (0–12, top to bottom in the form)
  const leaveTypeToBoxIdx = {
    "Vacation Leave": 0,
    "Mandatory/Forced Leave": 1,
    "Sick Leave": 2,
    "Maternity Leave": 3,
    "Paternity Leave": 4,
    "Special Privilege Leave": 5,
    "Solo Parent Leave": 6,
    "Study Leave": 7,
    "10-Day VAWC Leave": 8,
    "Rehabilitation Privilege": 9,
    "Special Leave Benefits for Women": 10,
    "Special Emergency (Calamity) Leave": 11,
    "Adoption Leave": 12,
  };

  // Each box's vertical bounds (in EMU, from the original VML path data)
  const boxBounds = [
    [0, 154939],         // 0 Vacation
    [187325, 342900],    // 1 Mandatory/Forced
    [374650, 530225],    // 2 Sick
    [561975, 717550],    // 3 Maternity
    [749300, 904874],    // 4 Paternity
    [937259, 1092199],   // 5 Special Privilege
    [1124584, 1280159],  // 6 Solo Parent
    [1311909, 1467484],  // 7 Study
    [1499869, 1654809],  // 8 VAWC
    [1687194, 1842769],  // 9 Rehab
    [1874519, 2030094],  // 10 SLBW
    [2061844, 2217419],  // 11 Calamity
    [2249169, 2412365],  // 12 Adoption
  ];

  // Build VML check stroke for a given box index — diagonal ✓ inside the box
  const buildCheckStroke = (boxIdx) => {
    const bounds = boxBounds[boxIdx];
    if (!bounds) return "";
    const [y0, y1] = bounds;
    const h = y1 - y0;
    const xLeft = 25000;
    const xMid = 65000;
    const xRight = 140000;
    const yMid = y0 + Math.round(h * 0.5);
    const yLow = y1 - 20000;
    const yHigh = y0 + 25000;
    // Two strokes: down-right then up-right, forming a checkmark
    return `m${xLeft},${yMid}l${xMid},${yLow}em${xMid},${yLow}l${xRight},${yHigh}e`;
  };

  // Identify which box (if any) to check
  const matchType = (l) => {
    const t = l.type || "";
    if (t.startsWith("Others:")) return null;
    if (leaveTypeToBoxIdx[t] !== undefined) return t;
    for (const k of Object.keys(leaveTypeToBoxIdx)) {
      if (t.includes(k) || k.includes(t)) return k;
    }
    return null;
  };
  const matchedType = matchType(leave);
  const boxIdx = matchedType !== null ? leaveTypeToBoxIdx[matchedType] : null;

  // (A) + (B): Edit the VML path + strip EMF fallback
  if (boxIdx !== null && boxIdx !== undefined) {
    // The big checkbox group is around offset 76714 in the original template.
    // Find the v:shape with the path attribute inside the first <w:pict> that contains "Group 7"
    // (or just look for the path with the unique signature "m,l,154939")
    const pathSignature = `m,l,154939`;
    const shapeMatch = xml.match(/<v:shape[^>]*\spath="([^"]*m,l,154939[^"]*)"[^>]*>/);
    if (shapeMatch) {
      const origPath = shapeMatch[1];
      const checkStroke = buildCheckStroke(boxIdx);
      const newPath = origPath + checkStroke;
      // Replace the path attribute
      const newShape = shapeMatch[0].replace(`path="${origPath}"`, `path="${newPath}"`);
      xml = xml.replace(shapeMatch[0], newShape);
      // Also strip the EMF fallback inside that group + shape
      // (we only strip in the area near our target to avoid side-effects)
      const groupStart = xml.indexOf(`<v:group`, xml.indexOf(`Group 7`) - 50);
      if (groupStart > 0) {
        const groupEnd = xml.indexOf(`</v:group>`, groupStart) + 10;
        let groupBlock = xml.slice(groupStart, groupEnd);
        groupBlock = groupBlock.replace(/\so:gfxdata="[^"]*"/g, "");
        xml = xml.slice(0, groupStart) + groupBlock + xml.slice(groupEnd);
      }
    }
  }

  // (C) Always also add a small inline ☑ marker before the label — backup in case VML doesn't render
  const checkRunPrefix = `<w:r><w:rPr><w:rFonts w:ascii="Arial Unicode MS" w:hAnsi="Arial Unicode MS"/><w:b/><w:sz w:val="20"/></w:rPr><w:t xml:space="preserve">☑ </w:t></w:r>`;
  const checkboxAnchors = {
    "Vacation Leave":                       `<w:t xml:space="preserve">Vacation Leave </w:t>`,
    "Mandatory/Forced Leave":               `<w:t xml:space="preserve">Mandatory/Forced </w:t>`,
    "Sick Leave":                           `<w:t>Sick Leave</w:t>`,
    "Maternity Leave":                      `<w:t xml:space="preserve">Maternity Leave </w:t>`,
    "Paternity Leave":                      `<w:t>Paternity Leave</w:t>`,
    "Special Privilege Leave":              `<w:t>Special</w:t>`,
    "Solo Parent Leave":                    `<w:t>Solo</w:t>`,
    "Study Leave":                          `<w:t>Study</w:t>`,
    "10-Day VAWC Leave":                    `<w:t>VAWC</w:t>`,
    "Rehabilitation Privilege":             `<w:t>Rehabilitation</w:t>`,
    "Special Leave Benefits for Women":     `<w:t xml:space="preserve">Special Leave Benefits for </w:t>`,
    "Special Emergency (Calamity) Leave":   `<w:t xml:space="preserve">Special Emergency (Calamity) Leave </w:t>`,
    "Adoption Leave":                       `<w:t xml:space="preserve">Adoption </w:t>`,
  };
  if (matchedType && checkboxAnchors[matchedType]) {
    const anchor = checkboxAnchors[matchedType];
    const firstIdx = xml.indexOf(anchor);
    if (firstIdx >= 0) {
      const runStart = xml.lastIndexOf("<w:r>", firstIdx) >= 0
        ? xml.lastIndexOf("<w:r>", firstIdx)
        : xml.lastIndexOf("<w:r ", firstIdx);
      if (runStart >= 0) {
        xml = xml.slice(0, runStart) + checkRunPrefix + xml.slice(runStart);
      }
    }
  }

  // "Others" types text injection (Wellness, Mental Health, Service Credits, CTO, "Others: <text>")
  const othersTypes = ["Wellness Leave", "Mental Health Leave", "Service Credits", "CTO"];
  let othersText = "";
  if (leave.type?.startsWith("Others:")) {
    othersText = leave.type.replace(/^Others:\s*/, "");
  } else if (othersTypes.includes(leave.type)) {
    othersText = leave.type;
  }
  if (othersText) {
    xml = xml.replace(
      `<w:t>Others:</w:t>`,
      `<w:t xml:space="preserve">Others: </w:t></w:r>${checkRunPrefix}<w:r><w:rPr><w:rFonts w:ascii="Arial"/><w:b/><w:sz w:val="16"/></w:rPr><w:t xml:space="preserve">${xe(othersText)}</w:t>`
    );
  }

  // ─── 9. 7.C "days with pay" — only fill if approved ───
  if (leave.status === "approved" || leave.status === "completed") {
    xml = xml.replace(`<w:t xml:space="preserve">days with </w:t>`, `<w:t xml:space="preserve">${xe(String(leave.days))} days with </w:t>`);
  }

  zip.file("word/document.xml", xml);

  return await zip.generateAsync({ type: "blob", mimeType: "application/vnd.openxmlformats-officedocument.wordprocessingml.document" });
}

// Phase 1: kept around for fallback testing
async function buildCS6Docx_v1(leave, withSig) {
  const JSZip = await loadJSZip();
  const resp = await fetch(CS6_TEMPLATE_URL);
  if (!resp.ok) throw new Error("Template fetch failed: HTTP " + resp.status);
  const buf = await resp.arrayBuffer();
  const zip = await JSZip.loadAsync(buf);
  return await zip.generateAsync({ type: "blob", mimeType: "application/vnd.openxmlformats-officedocument.wordprocessingml.document" });
}

