  /* ═══ CO SCHEDULE REQUEST (NEW FEATURE) ═══ */
  const COPage=()=>{
    const statusColors={pending:"#7D6608",approved:"#2E6B4F",completed:"#1B4D7E",declined:"#c0392b"};
    const statusBg={pending:"#fef9e7",approved:"#eafaf1",completed:"#e8f0fe",declined:"#fde8e8"};
    const mtList=users.filter(u=>u.position?.toLowerCase().includes("master")||u.position?.toLowerCase().includes("mt"));

    const addReq=()=>{if(!f.coDate?.trim())return;
      setCoRequests(prev=>[...prev,{id:uid(),requester:auth.name,role:auth.position||auth.role,date:f.coDate,time:f.coTime||"",section:f.coSec||"",subject:f.coSubj||"",observer:f.coObs||"School Head",notes:f.coNotes||"",status:"pending",dateCreated:now(),feedback:""}]);
      fr();setModal(null);};
    const updateStatus=(rid,status,feedback)=>{setCoRequests(prev=>prev.map(r=>r.id===rid?{...r,status,feedback:feedback||r.feedback,dateActioned:now()}:r));setModal(null);};

    const myRequests=isAdmin?coRequests:coRequests.filter(r=>r.requester===auth.name);
    const pending=coRequests.filter(r=>r.status==="pending");

    return(<><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
      <h2 style={{fontSize:20,fontWeight:700}}>CO Schedule {isAdmin&&<Badge color="#7D6608">{pending.length} pending</Badge>}</h2>
      {!isAdmin&&<Btn sm onClick={()=>{fr();setModal("addCO");}} color="#7D6608">{IC.plus} Request CO</Btn>}</div>
      <div style={{background:"#fef9e7",borderRadius:10,padding:12,marginBottom:14,fontSize:13,color:"#7D6608"}}>
        {isAdmin?<><strong>Admin view:</strong> Approve, decline, or mark CO requests as completed. Add feedback after observation.</>
          :<><strong>Request a Classroom Observation</strong> from the School Head or Master Teachers. Your request will be reviewed and scheduled.</>}</div>

      {myRequests.length===0&&<div style={{textAlign:"center",padding:32,color:"#ccc"}}>No CO requests yet.</div>}
      {myRequests.map(r=><div key={r.id} style={{background:"#fff",borderRadius:12,padding:14,marginBottom:8,borderLeft:`4px solid ${statusColors[r.status]}`}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
          <div><div style={{display:"flex",gap:6,alignItems:"center",marginBottom:4}}>
            <span style={{fontWeight:700,fontSize:15}}>{r.requester}</span>
            <span style={{fontSize:11,padding:"2px 8px",borderRadius:6,background:statusBg[r.status],color:statusColors[r.status],fontWeight:600,textTransform:"uppercase"}}>{r.status}</span></div>
            <div style={{fontSize:12,color:"#888"}}>Requested: {r.dateCreated}</div></div>
          {isAdmin&&r.status==="pending"&&<div style={{display:"flex",gap:4}}>
            <Btn sm color="#2E6B4F" onClick={()=>updateStatus(r.id,"approved")}>{IC.check} Approve</Btn>
            <Btn sm color="#c0392b" outline onClick={()=>updateStatus(r.id,"declined")}>Decline</Btn></div>}
          {isAdmin&&r.status==="approved"&&<Btn sm color="#1B4D7E" onClick={()=>{ff("coFeedback","");setModal(`coFB_${r.id}`);}}>Complete + Feedback</Btn>}</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginTop:8,fontSize:12}}>
          <div><span style={{color:"#999"}}>Date:</span> <strong>{r.date}</strong></div>
          <div><span style={{color:"#999"}}>Time:</span> <strong>{r.time||"TBD"}</strong></div>
          <div><span style={{color:"#999"}}>Observer:</span> <strong>{r.observer}</strong></div>
          <div><span style={{color:"#999"}}>Section:</span> <strong>{r.section||"—"}</strong></div>
          <div><span style={{color:"#999"}}>Subject:</span> <strong>{r.subject||"—"}</strong></div>
        </div>
        {r.notes&&<div style={{marginTop:6,fontSize:12,color:"#555",background:"#f9f9fb",borderRadius:6,padding:8}}>{r.notes}</div>}
        {r.feedback&&<div style={{marginTop:6,fontSize:12,color:"#1B4D7E",background:"#e8f0fe",borderRadius:6,padding:8}}><strong>Feedback:</strong> {r.feedback}</div>}</div>)}

      <Modal open={modal==="addCO"} onClose={()=>setModal(null)} title="Request Classroom Observation">
        <Inp label="Preferred Date" value={f.coDate||""} onChange={v=>ff("coDate",v)} type="date"/>
        <Inp label="Preferred Time" value={f.coTime||""} onChange={v=>ff("coTime",v)} ph="e.g. 9:00 AM - 10:00 AM"/>
        <Sel label="Observer" value={f.coObs||"School Head"} onChange={v=>ff("coObs",v)} options={["School Head",...mtList.map(m=>m.name),...(users.filter(u=>u.position?.toLowerCase().includes("master")).length===0?["Master Teacher (not yet added)"]:[])]}/>
        <Inp label="Section" value={f.coSec||""} onChange={v=>ff("coSec",v)} ph="e.g. Grade 3 - Orchid"/>
        <Inp label="Subject / Learning Area" value={f.coSubj||""} onChange={v=>ff("coSubj",v)} ph="e.g. Filipino, Mathematics"/>
        <Inp label="Notes / Special request" value={f.coNotes||""} onChange={v=>ff("coNotes",v)} ta ph="Any special arrangements needed..."/>
        <Btn onClick={addReq} full color="#7D6608">Submit Request</Btn></Modal></>);};

